/* PasstheEPPP — Question Bank Batch 46
   90 new questions — Mixed high-weight EPPP domains */
(function(){
    if (typeof EPPPData === 'undefined') return;

    const batch46 = [
        // === Treatment / Interventions (20) ===
        {domainId:6, q:"Prolonged Exposure (PE) therapy for PTSD involves:", options:["Strictly avoiding known trauma reminders to prevent triggering autonomic physiological arousal cascades","Repeated, detailed revisiting of the trauma memory (imaginal exposure) and approaching avoided situations (in vivo exposure)","Exclusively utilizing progressive muscle relaxation and diaphragmatic breathing exercises during sessions","Employing clinical hypnosis to access deeply repressed unconscious traumatic childhood memories"], answer:1, difficulty:"medium", rationale:"Correct: (B) PE (Foa): two core components — imaginal exposure (repeatedly recounting the trauma narrative aloud until distress decreases through habituation) and in vivo exposure (systematically approaching safe situations being avoided). One of the best-evidenced PTSD treatments.\n\nWhy others are wrong:\n(A) PE specifically targets avoidance — the maintenance mechanism of PTSD\n(C) While breathing retraining may be included, exposure is the active ingredient\n(D) Hypnosis is a separate modality not part of PE protocol"},
        {domainId:6, q:"Differential reinforcement of other behavior (DRO) involves:", options:["Consistently providing positive reinforcement immediately following the occurrence of problem behavior","Reinforcing the ABSENCE of the target behavior during a specifically designated continuous time interval","Systematically applying punishment procedures across all observable manifestations of negative behavior","Actively ignoring the client completely regardless of their current emotional or behavioral presentation"], answer:1, difficulty:"medium", rationale:"Correct: (B) DRO: reinforcement is delivered when the target (unwanted) behavior does NOT occur during a set interval. The client is reinforced for 'anything but' the problem behavior. Common in ABA for reducing challenging behaviors.\n\nWhy others are wrong:\n(A) DRO reinforces the ABSENCE of the problem behavior\n(C) DRO uses positive reinforcement, not punishment\n(D) Active monitoring and reinforcement are required"},
        {domainId:6, q:"Transtheoretical Model processes of change include:", options:["Exclusively observable external behavioral modification processes targeting immediate habit change","Experiential processes (e.g., consciousness raising) AND behavioral processes (e.g., counter-conditioning)","Only a single unvarying linear transformative psychological healing process across all stages","Strictly pharmacological and biological medication management processes during acute phases"], answer:1, difficulty:"medium", rationale:"Correct: (B) TTM processes: Experiential (used more in early stages — consciousness raising, dramatic relief, self-reevaluation, environmental reevaluation, social liberation) and Behavioral (used more in later stages — counter-conditioning, stimulus control, reinforcement management, helping relationships, self-liberation).\n\nWhy others are wrong:\n(A) Both experiential and behavioral processes are included\n(C) There are 10 processes of change\n(D) TTM is a psychosocial, not pharmacological, model"},
        {domainId:6, q:"Interpersonal therapy (IPT) for depression focuses on:", options:["Resolving deeply repressed unconscious childhood conflicts and persistent complex infantile fixations","Four interpersonal problem areas: grief, role disputes, role transitions, and interpersonal deficits","Systematically identifying and explicitly challenging pervasive cognitive distortions and schemas","Utilizing exhaustive symbolic dream analysis to uncover hidden intrapsychic instinctual desires"], answer:1, difficulty:"medium", rationale:"Correct: (B) IPT (Klerman & Weissman): time-limited (12-16 sessions), targets one of four problem areas: (1) Complicated grief, (2) Role disputes (conflicts), (3) Role transitions (life changes), (4) Interpersonal deficits (social isolation). Strong evidence for depression.\n\nWhy others are wrong:\n(A) IPT is interpersonal, not psychoanalytic (though psychoanalytically influenced)\n(C) Cognitive distortions → CBT\n(D) Dream analysis → psychoanalysis"},
        {domainId:6, q:"Narrative therapy (White & Epston) involves:", options:["Passively listening as clients dictate unstructured fictional stories without therapeutic intervention","Externalizing problems, identifying 'unique outcomes,' and fundamentally re-authoring dominant narratives","Implementing rigorous behavioral conditioning paradigms to shape observable prosocial interaction skills","Adjusting pharmacological medication management protocols based upon expressed qualitative narrative themes"], answer:1, difficulty:"medium", rationale:"Correct: (B) Narrative therapy: externalization (separating the person from the problem), identifying exceptions/unique outcomes (times the problem wasn't dominant), and re-authoring (constructing new, preferred narratives). Social constructionist approach.\n\nWhy others are wrong:\n(A) Narrative therapy uses stories therapeutically, not just storytelling\n(C) It's a postmodern/social constructionist approach, not behavioral\n(D) It's a psychotherapy, not pharmacotherapy"},
        {domainId:6, q:"Collaborative empiricism in CBT means:", options:["The therapist unilaterally dictates all specific treatment protocols and strict behavioral interventions","The therapist and client work together as a team to identify, test, and modify cognitive distortions","The client independently researches their symptoms alone without significant therapist guidance or input","Only published peer-reviewed academic empirical research studies count toward therapeutic progress"], answer:1, difficulty:"easy", rationale:"Correct: (B) Beck's CBT: collaborative empiricism — the therapist and client are co-investigators testing the validity of the client's beliefs through behavioral experiments, evidence gathering, and Socratic questioning. Neither dictatorial nor passive.\n\nWhy others are wrong:\n(A) CBT is collaborative, not directive in a top-down manner\n(C) It's a partnership, not solo work\n(D) 'Empiricism' here means using evidence in therapy, not academic research"},
        {domainId:6, q:"Functional analysis in behavior therapy identifies:", options:["Only the specific structural topography of the target outward behavioral manifestations","The antecedents, behavior, and consequences (ABC) that systematically maintain a target behavior","Only the specific long-term environmental consequences immediately following behavioral events","The client's deeply unconscious intrapsychic relational motivations driving maladaptive patterns"], answer:1, difficulty:"easy", rationale:"Correct: (B) Functional analysis (ABC model): Antecedent (what triggers the behavior), Behavior (the observable target behavior), Consequence (what follows and reinforces/punishes the behavior). Understanding the function guides intervention selection.\n\nWhy others are wrong:\n(A) All three components (A, B, C) are analyzed\n(C) Antecedents are equally important as consequences\n(D) Functional analysis is behavioral, not psychodynamic"},
        {domainId:6, q:"Acceptance in ACT stands for:", options:["Globally giving up and completely surrendering to pathological or maladaptive cognitive patterns","Willingness to experience internal events (thoughts, feelings) without trying to change or control them","Enthusiastically approving of absolutely everything that occurs throughout daily life transitions","Exhibiting entirely passive resignation toward inevitably worsening physiological or clinical symptoms"], answer:1, difficulty:"medium", rationale:"Correct: (B) ACT acceptance: actively and openly receiving internal experiences. Not resignation or approval of suffering — but willingness to have difficult experiences when they arise in service of valued living. Opposite of experiential avoidance.\n\nWhy others are wrong:\n(A) Acceptance is active willingness, not giving up\n(C) Approving is not required — accepting painful experiences doesn't mean liking them\n(D) ACT promotes committed action, not passive resignation"},
        {domainId:6, q:"The 'miracle question' in Solution-Focused Brief Therapy asks:", options:["Extensively about the client's complex traumatic early childhood developmental history","'If a miracle happened tonight and the problem was solved, what would be different tomorrow?'","Specifically about experiencing unexpected idiosyncratic medication side effects during treatment","Broadly about understanding complex technical specifications of their psychiatric diagnosis"], answer:1, difficulty:"easy", rationale:"Correct: (B) The miracle question: helps clients envision their preferred future without the problem, identify observable differences, and generate goals. It shifts focus from problem analysis to solution construction.\n\nWhy others are wrong:\n(A) SFBT is future-focused, not history-focused\n(C)(D) The miracle question is about envisioning solutions, not medical/diagnostic topics"},
        {domainId:6, q:"Bowen's concept of differentiation of self refers to:", options:["Literally achieving permanent geographic physical separation from all extended family members","Maintaining one's own thinking and sense of self while remaining emotionally connected to others","Developing complete absolute emotional detachment from all interpersonal familial relationships","Only enhancing advanced complex rational conceptual planning and logical cognitive function"], answer:1, difficulty:"medium", rationale:"Correct: (B) Differentiation (Bowen): maintaining a solid sense of self (thinking, beliefs, values) while staying emotionally engaged with others. Low differentiation → emotional fusion (losing self in relationships) or emotional cutoff (complete avoidance). High differentiation → flexible, autonomous relating.\n\nWhy others are wrong:\n(A) Physical separation is geographic, not psychological\n(C) Emotional cutoff is the pathological opposite of healthy differentiation\n(D) Differentiation involves both cognitive and emotional dimensions"},
        {domainId:6, q:"Stimulus generalization occurs when:", options:["A specific conditioned response reliably occurs only upon exposure to the single original stimulus","A conditioned response readily occurs upon exposure to novel stimuli SIMILAR to the original CS","The previously established conditioned response is completely extinguished through repeated trials","No measurable physiological or behavioral psychological response reliably occurs at all"],"answer":1, difficulty:"easy", rationale:"Correct: (B) Stimulus generalization: the CR occurs to stimuli resembling the CS. Little Albert (Watson): fear conditioned to a white rat generalized to other furry objects (rabbit, fur coat, Santa beard). Gradient: more similar stimuli elicit stronger responses.\n\nWhy others are wrong:\n(A) Response only to the original stimulus = stimulus discrimination\n(C) Extinction is the weakening of the CR through unreinforced presentations of the CS\n(D) Generalization produces responses, not absent responses"},
        {domainId:6, q:"Crisis intervention is typically:", options:["An extensive long-term exploratory therapy enduring over multiple years of practice","Brief (6-10 sessions), focused on immediate stabilization, safety, and restoring pre-crisis functioning","Exclusively mandated for profoundly psychotic involuntarily committed psychiatric patients","Consistently proven to be completely ineffective regarding trauma mitigation and recovery"], answer:1, difficulty:"easy", rationale:"Correct: (B) Crisis intervention: short-term, immediate focus on safety, stabilization, and coping. Goals: reduce acute distress, restore equilibrium, connect to ongoing resources. Based on crisis theory (Caplan): people in crisis are more open to intervention.\n\nWhy others are wrong:\n(A) Crisis intervention is specifically brief and immediate\n(C) Crisis intervention applies to anyone experiencing a crisis\n(D) Crisis intervention has strong evidence of effectiveness"},
        {domainId:6, q:"Rational Emotive Behavior Therapy (REBT, Ellis) primarily targets:", options:["Only changing explicitly observable external environmental behavioral manifestations","Irrational beliefs using the ABC model, directly disputing these beliefs to reduce emotional distress","Only modifying intense pathological emotions without engaging underlying rational cognition","Using unstructured symbolic dream interpretation aiming to unearth repressed childhood content"], answer:1, difficulty:"easy", rationale:"Correct: (B) REBT (Ellis): ABC(DE) model: Activating event → Beliefs (irrational: demandingness, catastrophizing, frustration intolerance, global evaluation) → Consequences (emotional/behavioral). Disputing (D) irrational beliefs leads to new Effects (E).\n\nWhy others are wrong:\n(A) REBT integrates cognition, emotion, and behavior\n(C) Cognition (beliefs) is the primary treatment target\n(D) Dream interpretation → psychoanalysis"},
        {domainId:6, q:"Social skills training typically involves:", options:["Only pharmacological medication management focusing upon underlying neurotransmitter balancing","Instruction, modeling, behavior rehearsal/role-play, feedback, and structured homework assignments","Only passively reading theoretical psychoeducational materials covering optimal social skills","Systematically avoiding and escaping highly stressful anxiety-inducing interaction situations"], answer:1, difficulty:"easy", rationale:"Correct: (B) SST components: psychoeducation (instruction), modeling (demonstrating the skill), behavioral rehearsal (role-playing), feedback (from therapist and group), and homework (real-world practice). Used for social anxiety, schizophrenia, ASD, ADHD.\n\nWhy others are wrong:\n(A) SST is a psychosocial intervention\n(C) Reading alone is insufficient — practice is essential\n(D) The goal is to approach, not avoid, social situations"},
        {domainId:6, q:"Experiential avoidance (ACT concept) refers to:", options:["Actively avoiding completely new unforeseen objective environmental external experiences","Attempting to avoid or escape unwanted internal experiences like thoughts, feelings, and sensations","Being completely nonjudgmentally open toward absolutely every internal psychological experience","Only intentionally avoiding specific objectively dangerous phobic environmental stimulus objects"], answer:1, difficulty:"medium", rationale:"Correct: (B) Experiential avoidance: unwillingness to remain in contact with aversive private experiences and taking action to change or escape them. ACT views EA as a core process underlying many psychological problems — the attempts to control internal events paradoxically increase suffering.\n\nWhy others are wrong:\n(A) It's specifically about INTERNAL experiences, not external novelty\n(C) EA is the OPPOSITE of experiential openness/acceptance\n(D) EA applies to any unwanted internal experience, not just phobic stimuli"},
        {domainId:6, q:"Multimodal therapy (Lazarus) uses the BASIC ID to assess:", options:["Strictly observable environmental target behavior consequences maintaining current dysfunction","Behavior, Affect, Sensation, Imagery, Cognition, Interpersonal functioning, and Drugs/biology","Only isolated cognitive distortion processing patterns perpetuating acute clinical depression","Only maladaptive pathological interpersonal communication relationship deterioration patterns"], answer:1, difficulty:"medium", rationale:"Correct: (B) BASIC ID: systematic assessment across seven modalities — Behavior, Affect, Sensation, Imagery, Cognition, Interpersonal, Drugs/biology. Treatment is tailored to address the client's specific modality profile, drawing from multiple theoretical approaches.\n\nWhy others are wrong:\n(A)(C)(D) All seven modalities are assessed — BASIC ID is comprehensive"},
        {domainId:6, q:"Contingency contracting involves:", options:["Intentionally breaking a previously established informal behavioral contract unexpectedly","A formal written agreement specifying the exact relationship between behaviors and consequences","Vague unstructured verbal agreements completely lacking specific consequences or rewards","Providing entirely unconditional positive reinforcement regardless of behavioral presentation"], answer:1, difficulty:"easy", rationale:"Correct: (B) Contingency contract: a specific, written document detailing: target behavior, reinforcement for meeting the goal, consequences for not meeting it, method of monitoring, and signatures. Makes expectations and contingencies explicit.\n\nWhy others are wrong:\n(A) Contracts are designed to be upheld\n(C) Written contracts are more effective than verbal agreements\n(D) Reinforcement is contingent on specific behaviors — that's the point"},
        {domainId:6, q:"The concept of 'corrective emotional experience' (Alexander) refers to:", options:["Correcting an ongoing psychiatric pharmacological medication dosage to achieve stabilization","Experiencing a new, healthier emotional response in therapy that differs from original relationships","Taking a psychological educational academic assessment test repeatedly to achieve higher scoring","Undergoing severe emotional correction via operant punishment behavioral conditioning paradigms"], answer:1, difficulty:"medium", rationale:"Correct: (B) Alexander: the therapist provides a relationship experience that emotionally corrects the damaging effects of earlier relationships. If a client expected criticism (like from a harsh parent), receiving acceptance from the therapist creates a new relational template.\n\nWhy others are wrong:\n(A) Pharmacological, not psychotherapeutic\n(C) Test-taking, not therapy\n(D) The corrective experience is positive, not punitive"},
        {domainId:6, q:"Guided imagery involves:", options:["Watching commercially available broadcast television addressing relevant developmental topics","Using directed mental visualization to systematically promote relaxation, healing, or behavior change","Only engaging entirely unstructured deep diaphragmatic physiological breathing exercises","Undergoing high-resolution structural systemic functioning MRI neuroimaging scanning protocols"], answer:1, difficulty:"easy", rationale:"Correct: (B) Guided imagery: the therapist verbally guides the client through detailed mental images (peaceful scenes, rehearsing coping, visualizing healing). Used for pain management, anxiety reduction, performance enhancement, and trauma processing.\n\nWhy others are wrong:\n(A) Guided imagery is internal visualization, not external media\n(C) While breathing may be combined, imagery is the primary component\n(D) MRI is a medical imaging technique, not a therapeutic intervention"},
        {domainId:6, q:"Multisystemic Therapy (MST) for juvenile offenders targets:", options:["Only the individual youth deliberately detached completely from their surrounding environment","Multiple overlapping systems — family, peers, school, community — contributing to the behavior","Only highly specific structural academic achievement performance within the school classroom","Only acute physiological systemic biological withdrawal originating from severe substance use"], answer:1, difficulty:"medium", rationale:"Correct: (B) MST (Henggeler): an intensive, home-based intervention addressing the multiple systems influencing the youth's behavior — family dynamics, peer relationships, school functioning, and community factors. Empowers caregivers as change agents. Strong evidence for reducing recidivism.\n\nWhy others are wrong:\n(A) MST explicitly targets all systems affecting the youth\n(C)(D) School and substances are addressed as part of the broader systemic intervention"},


        // === Clinical / Diagnosis (15) ===
        // === Clinical / Diagnosis (15) ===
        {domainId:7, q:"Specific Learning Disorder in DSM-5 replaces:", options:["Attention-Deficit/Hyperactivity Disorder across all developmental age ranges","Separate diagnoses of reading disorder, mathematics disorder, and written expression","Unspecified global Intellectual Disability and related cognitive pervasive deficits","Autism Spectrum Disorder and associated persistent social communication difficulties"], answer:1, difficulty:"medium", rationale:"Correct: (B) DSM-5 unified the separate DSM-IV learning disorders into one diagnosis (Specific Learning Disorder) with specifiers: with impairment in reading (dyslexia), in written expression (dysgraphia), or in mathematics (dyscalculia).\n\nWhy others are wrong:\n(A) ADHD remains a separate diagnosis\n(C) ID is a separate neurodevelopmental disorder\n(D) ASD is a separate diagnosis"},
        {domainId:7, q:"Illness Anxiety Disorder (formerly hypochondriasis, somatic subtype) involves:", options:["Possessing an already extensively confirmed and documented severe medical condition","Preoccupation with having or acquiring a serious illness with MINIMAL or NO somatic symptoms","Conscious factitious psychological or physical symptom production for secondary gains","Pervasive neurological conversion symptoms selectively altering voluntary sensory motor function"], answer:1, difficulty:"medium", rationale:"Correct: (B) IAD: preoccupation with illness, high health anxiety, excessive health behaviors or maladaptive avoidance, with little or no somatic symptoms (distinguishing it from Somatic Symptom Disorder, which requires distressing somatic symptoms).\n\nWhy others are wrong:\n(A) The concern is disproportionate to any actual medical findings\n(C) Factitious disorder involves intentional symptom production\n(D) Conversion involves neurological-like symptoms"},
        {domainId:7, q:"The negative symptoms of schizophrenia include:", options:["Persistent auditory hallucinations alongside rigidly held bizarre persecutory delusions","Flat affect, alogia (poverty of speech), avolition (lack of motivation), and asociality","Highly disorganized speech accompanied by profoundly inappropriate emotional affect","Suspicious paranoid ideas selectively targeting immediate familial relationship figures"], answer:1, difficulty:"medium", rationale:"Correct: (B) Negative symptoms reflect a DECREASE or absence of normal functioning: flat/blunted affect, alogia, avolition, anhedonia, asociality. Harder to treat than positive symptoms and often predict poorer long-term functioning.\n\nWhy others are wrong:\n(A) Hallucinations and delusions are POSITIVE symptoms\n(C) Disorganized speech is a disorganized/positive symptom\n(D) Paranoid ideas are positive symptoms"},
        {domainId:7, q:"Panic Disorder involves:", options:["Persistent widespread low-level generalized worry regarding everyday routine life events","Recurrent, unexpected panic attacks with persistent concern about additional attacks","Only explicitly situational panic attacks provoked directly by specific external triggers","Exclusively nighttime physiological symptoms occurring strictly during deep slow-wave sleep"], answer:1, difficulty:"easy", rationale:"Correct: (B) Panic Disorder: recurrent UNEXPECTED panic attacks + at least 1 month of persistent worry about more attacks, worry about consequences ('I'm going crazy,' 'having a heart attack'), or maladaptive behavioral changes (avoidance). Expected panic attacks alone don't qualify.\n\nWhy others are wrong:\n(A) Persistent worry = GAD\n(C) Situational attacks may indicate specific phobia or social anxiety\n(D) Attacks can occur anytime, including from sleep (nocturnal panic)"},
        {domainId:7, q:"Disruptive Mood Dysregulation Disorder (DMDD) was created to:", options:["Functionally replace all conventional bipolar disorder diagnoses observed within adult populations","Address the overdiagnosis of bipolar disorder in children by providing a category for severe irritability","Permanently rename and fundamentally conceptually restructure the foundational clinical ADHD criteria","Be utilized exclusively during narrow developmental windows strictly within adolescent populations"], answer:1, difficulty:"medium", rationale:"Correct: (B) DMDD (new in DSM-5): for children 6-18 with severe, chronic irritability and frequent temper outbursts disproportionate in intensity/duration. Created because many irritable children were being diagnosed with pediatric bipolar — DMDD provides a more appropriate category.\n\nWhy others are wrong:\n(A) Bipolar disorder in adults remains unchanged\n(C) ADHD is a separate diagnosis\n(D) DMDD is for children 6-18 (cannot be first diagnosed before 6 or after 18)"},
        {domainId:7, q:"Persistent Depressive Disorder (Dysthymia) requires:", options:["Severe depressive clinical mood episodes consistently lasting for exactly two weeks","Depressed mood for MOST DAYS for at least 2 YEARS (adults) or 1 year (children/adolescents)","Only three consecutive days of profoundly noticeable severe emotional depressive affect","Depressive symptomatology emerging exclusively throughout dark winter seasonal months"], answer:1, difficulty:"easy", rationale:"Correct: (B) PDD (DSM-5 consolidation of dysthymia + chronic MDD): depressed mood most days, more days than not, for ≥2 years (adults) or ≥1 year (children/adolescents). Plus ≥2 additional symptoms. Never free of symptoms for >2 months.\n\nWhy others are wrong:\n(A) 2 weeks is the MDD episode duration requirement\n(C) 3 days is far too short\n(D) Winter-specific = seasonal pattern specifier"},
        {domainId:7, q:"Excoriation (Skin-Picking) Disorder is classified in DSM-5 under:", options:["Generalized Anxiety and Stressor-Related Pathological Disorders Chapter","Obsessive-Compulsive and Related Disorders (OCD) Diagnostic Chapter","Severe Complex Trauma and Explicitly Stressor-Related Disorders Chapter","Disruptive Impulse Control and Specific Conduct Behavioral Disorders Chapter"], answer:1, difficulty:"easy", rationale:"Correct: (B) Excoriation Disorder: recurrent skin picking resulting in skin lesions, with repeated attempts to stop, causing distress/impairment. Classified alongside OCD, BDD, hoarding, and trichotillomania as OCD-related conditions.\n\nWhy others are wrong:\n(A)(C)(D) All are separate DSM-5 chapters"},
        {domainId:7, q:"Unspecified and Other Specified diagnoses in DSM-5 replace:", options:["Virtually all previously established classical functional analytical diagnostic categories","'NOS' (Not Otherwise Specified) diagnostic classifications formerly utilized in DSM-IV","Only the specifically severe and prolonged paranoid disorganized psychotic disorders","All distinct established clinically recognized Axis II personality disorder functioning diagnoses"], answer:1, difficulty:"easy", rationale:"Correct: (B) DSM-IV's NOS → DSM-5's two categories: 'Other Specified' (clinician specifies the reason for not meeting full criteria) and 'Unspecified' (clinician does NOT specify the reason). Provides more flexibility and documentation clarity.\n\nWhy others are wrong:\n(A)(C)(D) This change applies broadly across all diagnostic categories"},
        {domainId:7, q:"Conduct Disorder is characterized by:", options:["Only specific manifestations involving acute severe social anxiety symptoms and extensive avoidance","A repetitive pattern of violating the basic rights of others or major age-appropriate societal norms","Only strictly neurovegetative severe depressive symptoms persisting across extended durations","Only pervasive extreme and unmanageable hyperactive behavioral impulsivity affecting academics"], answer:1, difficulty:"easy", rationale:"Correct: (B) CD: four symptom clusters — aggression to people/animals, destruction of property, deceitfulness/theft, and serious rule violations. Specifiers: childhood-onset (<10), adolescent-onset, or unspecified. With or without limited prosocial emotions (callous-unemotional traits).\n\nWhy others are wrong:\n(A) Anxiety → anxiety disorders\n(C) Depression → depressive disorders\n(D) Hyperactivity → ADHD"},
        {domainId:7, q:"Hoarding Disorder is now classified:", options:["Exclusively as a highly specific symptomatic presentation fundamentally placed under OCD itself","As its own distinct independent diagnosis within the OCD and Related Disorders chapter","Merely as a non-pathological highly rigid and inflexible enduring persistent personality trait","Under generalized severe social and specific phobia-related generalized anxiety disorders"], answer:1, difficulty:"easy", rationale:"Correct: (B) DSM-5: Hoarding Disorder is a separate diagnosis in the OCD-related chapter (previously a criterion of OCPD or OCD subtype). Characterized by persistent difficulty discarding possessions, accumulation, and clutter causing distress/impairment.\n\nWhy others are wrong:\n(A) Hoarding is a separate diagnosis, not a subtype of OCD\n(C) It's a full clinical diagnosis, not just a personality trait\n(D) It's in the OCD-related chapter, not anxiety disorders"},
        {domainId:7, q:"Tic Disorders are classified under:", options:["Generalized Anxiety and Specific Pathological Phobia Symptom Disorders","Neurodevelopmental Disorders specifically designated under Motor Disorders","Severe Persistent Paranoid Delusional and Disorganized Psychotic Disorders","Enduring Inflexible Axis II Complex Borderline Personality Disorders"], answer:1, difficulty:"easy", rationale:"Correct: (B) DSM-5: Tic Disorders (Tourette's, Persistent Motor or Vocal, Provisional) are classified under Neurodevelopmental Disorders → Motor Disorders. Tourette's: multiple motor + ≥1 vocal tic for >1 year, onset before 18.\n\nWhy others are wrong:\n(A)(C)(D) Tic disorders are specifically neurodevelopmental"},
        {domainId:7, q:"The kindling hypothesis of bipolar disorder suggests that:", options:["Environmental psychosocial stress acts as completely irrelevant regarding subsequent manic episodes","Early episodes are stress-triggered, but later episodes may occur spontaneously as illness progresses","Only fundamental biological inherited genetic determinants reliably drive bipolar symptomatology","Proactive pharmacological clinical intervention remains completely unnecessary for bipolar disorders"], answer:1, difficulty:"hard", rationale:"Correct: (B) Kindling (Post): initial mood episodes are triggered by identifiable stressors, but with each episode the brain becomes sensitized, eventually producing episodes without external triggers. Supports early, aggressive treatment to prevent kindling/progression.\n\nWhy others are wrong:\n(A) Stress is especially relevant to early episodes\n(C) The kindling model integrates stress-biology interaction, not just genetics\n(D) Early treatment is actually critical to prevent kindling"},
        {domainId:7, q:"Capgras delusion is the belief that:", options:["One possesses genuinely infinite immortal divine omnipotent powers establishing oneself as God","A familiar person has been systematically replaced by an indistinguishable identical impostor","One's physical body has become entirely structurally infested with invisible destructive parasites","One is literally biologically deceased and currently walking among surviving earthly individuals"], answer:1, difficulty:"hard", rationale:"Correct: (B) Capgras: the delusional belief that a familiar person (spouse, parent) has been replaced by an identical-looking impostor. May involve disconnection between facial recognition (intact) and emotional recognition (impaired). Associated with schizophrenia, dementia, TBI.\n\nWhy others are wrong:\n(A) Believing one is God = grandiose delusion\n(C) Parasitic infestation = delusional parasitosis (Ekbom syndrome)\n(D) Belief that one is dead = Cotard delusion"},
        {domainId:7, q:"The bimodal age of onset for anxiety disorders is:", options:["Consistently exclusively observed deep into advanced stages encompassing late human adulthood","Childhood/adolescence and middle age (some anxiety disorders peak early, others in later adulthood)","Only explicitly identifiable occurring directly postnatally completely immediately following live birth","Only systematically identifiable solely across highly specific highly isolated elderly populations"], answer:1, difficulty:"medium", rationale:"Correct: (B) Many anxiety disorders begin in childhood (specific phobias, separation anxiety, social anxiety — median onset 7-13) while others tend to onset later (GAD, panic disorder — median onset 20s-30s). Overall, anxiety disorders are among the earliest-onset mental disorders.\n\nWhy others are wrong:\n(A) Anxiety disorders commonly begin early, not late\n(C)(D) Not exclusively at birth or in elderly populations"},
        {domainId:7, q:"The 'four Ds' of psychopathology used for defining abnormal behavior are:", options:["Diagnosis, drugs, disease, and fundamental life-limiting interpersonal disability","Deviance, distress, dysfunction, and potentially immediate severe physical danger","Denial, depression, delusion, and profound fragmented cognitive dissociation","Doubt, delay, defeat, and overwhelming pervasive clinical emotional despair"], answer:1, difficulty:"easy", rationale:"Correct: (B) The four Ds: (1) Deviance (statistically or socially unusual), (2) Distress (causing suffering), (3) Dysfunction (impaired daily functioning), (4) Danger (risk to self or others). No single D is sufficient; most definitions of abnormality involve multiple Ds.\n\nWhy others are wrong:\n(A)(C)(D) These don't represent the standard conceptual framework for defining abnormality"},

        // === Assessment (10) ===
        {domainId:5, q:"The MCMI-IV (Millon Clinical Multiaxial Inventory) is designed to:", options:["Measure global highly fluid cognitive intelligence encompassing comprehensive executive functioning","Assess personality disorders and clinical syndromes aligned with DSM-5 and Millon's evolutionary theory","Test foundational academic achievement performance strictly across primary educational environments","Measure isolated short-term memory capacity and complex declarative verbal associative learning"], answer:1, difficulty:"medium", rationale:"Correct: (B) MCMI-IV: personality-focused inventory aligned with Millon's personality theory and DSM. Clinical Personality Patterns scales, Severe Personality Pathology scales, Clinical Syndrome scales, and Severe Clinical Syndrome scales. Uses Base Rate scores.\n\nWhy others are wrong:\n(A) Intelligence → WAIS, WISC\n(C) Achievement → WJ, WIAT\n(D) Memory → WMS, CVLT"},
        {domainId:5, q:"The Vineland Adaptive Behavior Scales measure:", options:["Standardized psychometric intelligence quotients testing multiple core cognitive processing domains","Adaptive behavior across communication, daily living skills, socialization, and motor skills","Enduring psychological personality traits exploring intrapsychic defensive functioning patterns","Comprehensive structural academic achievement strictly focusing upon language and mathematics"], answer:1, difficulty:"easy", rationale:"Correct: (B) Vineland-3: semi-structured interview measuring adaptive behavior in four domains — Communication, Daily Living Skills, Socialization, and Motor Skills. Essential for diagnosing Intellectual Disability (adaptive functioning criterion).\n\nWhy others are wrong:\n(A) Intelligence → IQ tests (WAIS, WISC)\n(C) Personality → MMPI, PAI\n(D) Achievement → WJ, WIAT"},
        {domainId:5, q:"Split-half reliability assesses:", options:["Test-retest temporal stability measuring longitudinal consistency across multiple administration points","Internal consistency by correlating scores from two systematically divided halves of the same test","Inter-rater observational agreement verifying scoring consensus between multiple independent evaluators","Concurrent predictive criterion validity establishing future expected behavioral outcome measures"], answer:1, difficulty:"easy", rationale:"Correct: (B) Split-half: divide the test into two halves (typically odd/even items), score each half separately, and correlate the two scores (then apply Spearman-Brown correction for full test length). Estimates internal consistency using a single administration.\n\nWhy others are wrong:\n(A) Test-retest requires two administrations\n(C) Inter-rater requires multiple raters\n(D) Predictive validity requires a criterion measured later"},
        {domainId:5, q:"The Halstead-Reitan Neuropsychological Battery includes:", options:["Only one single comprehensive global intelligence test establishing overarching cognitive capacity","Multiple tests including Category Test, Tactual Performance Test, Rhythm Test, and Finger Tapping","Only unstructured qualitative projective personality measures revealing unconscious psychological content","Only specialized localized memory tests targeting specifically hippocampal associative consolidation"], answer:1, difficulty:"medium", rationale:"Correct: (B) Halstead-Reitan: comprehensive neuropsychological battery developed for detecting brain damage. Yields an Impairment Index. Used alongside common clinical tests (WAIS, MMPI, Trail Making) for thorough neuropsychological evaluation.\n\nWhy others are wrong:\n(A) It's a comprehensive battery of multiple tests\n(C) It assesses neuropsychological function, not personality\n(D) Memory is one component; the battery assesses multiple cognitive domains"},
        {domainId:5, q:"Alternate forms reliability controls for:", options:["Internal item-level structural consistency identifying poorly discriminating individual test questions","Practice effects and content contamination resulting directly from repeated exposure to identical test items","Subjective clinical rater bias emerging during unstructured observational behavioral data collection","Superficial structural face validity concerning the apparent relevance of presented stimulus materials"], answer:1, difficulty:"medium", rationale:"Correct: (B) Alternate (parallel) forms: two equivalent versions of the test given to the same group. Controls for practice effects, memory of items, and content sampling. The correlation between forms estimates reliability.\n\nWhy others are wrong:\n(A) Internal consistency → Cronbach's alpha or split-half\n(C) Rater bias → inter-rater reliability measures\n(D) Face validity is about test appearance, not reliability"},
        {domainId:5, q:"The PCL-5 (PTSD Checklist) is a:", options:["Comprehensive structured multiphasic clinical personality inventory measuring pervasive pathology","Self-report measure of PTSD symptom severity fundamentally aligned with core DSM-5 diagnostic criteria","Standardized global intellectual intelligence test utilized strictly within forensic psychological settings","Qualitative unstructured projective diagnostic test identifying severe early developmental attachment trauma"], answer:1, difficulty:"easy", rationale:"Correct: (B) PCL-5: 20-item self-report corresponding to DSM-5 PTSD criteria (intrusions, avoidance, negative cognitions/mood, arousal/reactivity). Used for screening, provisional diagnosis, and monitoring symptom change during treatment.\n\nWhy others are wrong:\n(A) It specifically measures PTSD, not personality broadly\n(C) It measures symptoms, not intelligence\n(D) It's a structured self-report, not projective"},
        {domainId:5, q:"Test bias exists when:", options:["A standardized psychological test is perceived as subjectively exceedingly difficult by all participants","A test systematically over- or under-predicts performance for a particular demographic subgroup","The psychological test contains an overwhelmingly large number of lengthy complicated verbal items","Assessment scores are observed to be perfectly normally distributed across all measurable populations"], answer:1, difficulty:"medium", rationale:"Correct: (B) Test bias: systematic error in prediction for a specific group. If a test predicts job performance well for Group A but poorly for Group B, it's biased against Group B. Distinguished from test fairness (a broader social/ethical concept).\n\nWhy others are wrong:\n(A) Difficulty is not bias — a hard test can be unbiased\n(C) Item number is about length, not bias\n(D) Normal distribution doesn't indicate or preclude bias"},
        {domainId:5, q:"The California Verbal Learning Test (CVLT) assesses:", options:["Enduring structured personality traits mapping complex underlying implicit interrelational motivations","Verbal learning and memory strategies across multiple trials, interference, and delay conditions","Fine detailed structural motor coordination skills predominantly utilizing standardized pegboard tasks","Global visuospatial constructional processing capacity utilizing complex drawing replication exercises"], answer:1, difficulty:"medium", rationale:"Correct: (B) CVLT: 16-word list presented over 5 trials. Assesses learning curve, serial position effects, semantic vs. serial clustering strategies, proactive and retroactive interference (with a distractor list), short and long delay recall, and recognition. Rich neuropsychological data.\n\nWhy others are wrong:\n(A) Personality → MMPI, PAI\n(C) Motor skills → finger tapping, Purdue Pegboard\n(D) Visual perception → visual processing tests, Rey Complex Figure"},
        {domainId:5, q:"Standard scores (z-scores, T-scores, IQ scores) all share:", options:["The exact mathematically identical central mean value regardless of the specific measurement scale utilized","A known, fixed mathematical relationship to the mean and standard deviation of the normative distribution","The identical precise quantitative numeric scale range bounding minimum and maximum measurable limits","Structurally identical fundamental raw score statistical requirements across distinct diagnostic populations"], answer:1, difficulty:"medium", rationale:"Correct: (B) All standard scores locate an individual relative to the distribution's mean and SD. Z-score: M=0, SD=1. T-score: M=50, SD=10. IQ: M=100, SD=15. They're mathematically interconvertible.\n\nWhy others are wrong:\n(A) They have DIFFERENT means (0, 50, 100)\n(C) They have different ranges\n(D) Raw scores depend on the specific test"},
        {domainId:5, q:"The Luria-Nebraska Neuropsychological Battery is:", options:["A purely qualitative unstructured subjective projective theoretical personality assessment instrument","A standardized neuropsychological battery based on Luria's theory covering multiple cognitive domains","A traditional intelligence test focusing exclusively on estimating overarching global cognitive capacity","A strictly observational unstandardized behavioral rating scale completed exclusively by care providers"], answer:1, difficulty:"medium", rationale:"Correct: (B) Luria-Nebraska: 11 clinical scales (motor functions, rhythm, tactile functions, visual functions, receptive/expressive speech, writing, reading, arithmetic, memory, intellectual processes). Based on Luria's qualitative approach, standardized by Golden.\n\nWhy others are wrong:\n(A) It assesses neuropsychological function, not personality\n(C) Intelligence is one component of the battery\n(D) It's a directly administered test battery, not a rating scale"},

        // === Bio/Research/Social/Development (10) ===
        {domainId:1, q:"Mirror neurons fire both when:", options:["Only observing a specific structured behavioral action without independent engagement","An organism performs an action AND when it observes the same action performed by another","Only during deep slow-wave restful sleep cycles facilitating crucial memory consolidation","Only during fundamental biological survival-oriented behavior such as feeding or eating"], answer:1, difficulty:"medium", rationale:"Correct: (B) Mirror neurons (discovered in macaque premotor cortex, Rizzolatti): fire during both action execution and action observation. Hypothesized to support imitation, empathy, theory of mind, and language. Still debated regarding exact function and extent in humans.\n\nWhy others are wrong:\n(A) They fire during BOTH observation and execution\n(C)(D) They respond to a wide range of actions, not just specific behaviors"},
        {domainId:4, q:"Adolescent egocentrism (Elkind) includes:", options:["Preoperational early childhood sensorimotor developmental cognitive conceptual egocentrism","The imaginary audience (constant judgment) and personal fable (uniqueness/invincibility)","Only pervasive foundational cognitive conservation task failures emerging across domains","Clinical pathological enduring adult narcissistic personality disorder symptomatology"], answer:1, difficulty:"easy", rationale:"Correct: (B) Elkind's adolescent egocentrism: Imaginary audience (belief that others are constantly watching/judging you → self-consciousness) and Personal fable (belief that your experiences are unique, you're invulnerable → risk-taking). Peaks in early adolescence.\n\nWhy others are wrong:\n(A) Sensorimotor egocentrism is Piaget's infancy concept\n(C) Conservation failures are preoperational, not adolescent\n(D) Adolescent egocentrism is developmental, not pathological narcissism"},
        {domainId:3, q:"Cognitive dissonance (Festinger) occurs when:", options:["Internal attitudes and expressive external behaviors remain consistently perfectly aligned","A person holds two or more contradictory cognitions, creating discomfort that motivates change","Individuals universally and consistently behave according to purely rational deliberate directives","Occurring exclusively within highly structured competitive group organizational environments"], answer:1, difficulty:"easy", rationale:"Correct: (B) Cognitive dissonance: inconsistency between attitudes, or between attitudes and behavior, produces discomfort. People reduce dissonance by changing attitudes, changing behavior, adding consonant cognitions, or minimizing importance.\n\nWhy others are wrong:\n(A) Dissonance specifically involves INCONSISTENCY\n(C) Dissonance shows that people are not always rational — they rationalize\n(D) Dissonance occurs within individuals, not only in groups"},
        {domainId:3, q:"The contact hypothesis (Allport) proposes that intergroup prejudice can be reduced by:", options:["Virtually any casual unstructured incidental contact occurring between diverse opposing groups","Contact under specific conditions: equal status, common goals, cooperation, and institutional support","Systematically avoiding all direct interpersonal intergroup contact to prevent acute conflict","Exclusively encouraging carefully modulated structured online digital interpersonal interaction"], answer:1, difficulty:"medium", rationale:"Correct: (B) Allport's conditions for effective contact: (1) Equal status between groups, (2) Common goals, (3) Intergroup cooperation (not competition), (4) Support from authorities/institutions. Without these conditions, contact may INCREASE prejudice.\n\nWhy others are wrong:\n(A) Casual contact is insufficient and may worsen prejudice\n(C) Avoidance prevents opportunities for positive interaction\n(D) The original theory applies to face-to-face contact; online contact research is more recent"},
        {domainId:1, q:"The anterior cingulate cortex (ACC) is primarily involved in:", options:["Processing fundamental rudimentary elementary primary visual sensory spatial information","Error detection, conflict monitoring, pain processing, and emotional behavioral regulation","Processing foundational basic elementary primary auditory acoustic sensory stimulation","Directly orchestrating peripheral automated reflexive somatic spinal motor nerve movements"], answer:1, difficulty:"medium", rationale:"Correct: (B) ACC: involved in error detection (when responses conflict), conflict monitoring (Stroop task), pain processing (affective component), emotional regulation, and decision-making. Dysfunction implicated in OCD, depression, and chronic pain.\n\nWhy others are wrong:\n(A) Vision → occipital cortex\n(C) Auditory → temporal lobe\n(D) Reflexes → spinal cord and brainstem"},
        {domainId:1, q:"Optogenetics is a neuroscience technique that:", options:["Exclusively actively measures cortical electrical brain wave spatial distribution patterns","Uses light to control genetically modified neurons, allowing precise neural circuit modulation","Only narrowly specifically studies the specialized structural anatomy surrounding the human eye","Constitutes a highly controversial unverified alternative holistic medical healing technique"], answer:1, difficulty:"hard", rationale:"Correct: (B) Optogenetics: neurons are genetically modified to express light-sensitive proteins (channelrhodopsins). Shining light on these neurons activates/inhibits them with millisecond precision. Revolutionized causal understanding of neural circuits in animal research.\n\nWhy others are wrong:\n(A) Brain wave measurement = EEG\n(C) Despite 'opto-' (light), it's a brain manipulation technique, not eye research\n(D) It's a rigorous neuroscience research tool"},
        {domainId:4, q:"Object permanence typically develops around:", options:["Immediately precisely following postnatal early infancy biological emergence and birth","8-12 months of age (coinciding directly with Piaget's specific sensorimotor substage 4)","Around chronological age 5 marking late early childhood cognitive developmental maturity","Late chronological adolescence approaching young adult developmental cognitive functioning"], answer:1, difficulty:"easy", rationale:"Correct: (B) Object permanence: understanding that objects continue to exist when out of sight. Develops around 8-12 months. Before this, 'out of sight, out of mind.' Piaget's substage 4 — the infant begins searching for hidden objects.\n\nWhy others are wrong:\n(A) Not present at birth — develops gradually\n(C) Age 5 is well past this milestone\n(D) Object permanence is an infancy achievement"},
        {domainId:4, q:"Theory of Mind (ToM) typically develops around age:", options:["Immediately postnatally specifically during early initial biological infant developmental birth","4-5 years of age (demonstrated successfully completing standard reliable false-belief tasks)","Exactly around 12 chronological years transitioning deeply into the early adolescent period","Strictly isolated purely completely throughout mature chronological chronological adulthood only"], answer:1, difficulty:"easy", rationale:"Correct: (B) ToM: understanding that others have mental states (beliefs, desires, intentions) different from one's own. The false belief task (Sally-Anne test) is typically passed around age 4-5. Earlier forms of social understanding appear earlier; full ToM continues developing.\n\nWhy others are wrong:\n(A) Joint attention and early social awareness appear in infancy, but ToM as measured by false belief tasks develops later\n(C)(D) Core ToM is established by school age, though it continues to develop in sophistication"},
        {domainId:3, q:"Social loafing occurs when:", options:["Individuals inherently intuitively actively work substantially harder collectively inside groups","Individuals exert appreciably LESS effort when working in a group compared to working alone","Individuals naturally systematically fundamentally become significantly more highly productive","Only occurring strictly inside highly explicitly structured hostile competitive environments"], answer:1, difficulty:"easy", rationale:"Correct: (B) Social loafing (Ringelmann, Latané): individual effort decreases in group tasks, especially when individual contributions can't be identified. Reduced by: making contributions identifiable, increasing task importance, using smaller groups, and fostering group cohesion.\n\nWhy others are wrong:\n(A) Working harder in groups = social facilitation (for simple tasks)\n(C) Social loafing REDUCES productivity per person\n(D) It occurs in cooperative tasks where contributions aren't individually identifiable"},
        {domainId:1, q:"Functional MRI (fMRI) measures brain activity by detecting:", options:["Gross electrical signals directly systematically emanating entirely off the cortical solid surface","Changes in blood oxygenation (BOLD signal) reliably effectively associated with neural activity","High-frequency ultrasonic structural sound waves bouncing precisely off deep cranial matter","Radioactively artificially introduced external specific highly noticeable biological active tracers"], answer:1, difficulty:"medium", rationale:"Correct: (B) fMRI: measures Blood-Oxygen-Level-Dependent (BOLD) signal. Active brain regions consume more oxygen → changes in the ratio of oxygenated/deoxygenated hemoglobin → detectable by MRI. Good spatial resolution, moderate temporal resolution.\n\nWhy others are wrong:\n(A) EEG measures electrical signals directly\n(C) Ultrasound uses sound waves\n(D) PET uses radioactive tracers"}
    ];

    batch46.forEach(q => {
        const domain = EPPPData.domains.find(d => d.id === q.domainId);
        if (domain) {
            domain.questions.push({
                q: q.q, options: q.options, answer: q.answer,
                difficulty: q.difficulty, rationale: q.rationale,
                domainId: q.domainId, domainName: domain.name
            });
        }
    });

    console.log(`PasstheEPPP: Loaded ${batch46.length} additional questions (batch 46).`);
})();
